  showLoadingOnAmounts?: boolean;
  showOtherInput?: boolean;
};

type ThemeButtonProps = {
  amount: string | number | undefined;
  bgColor?: string;
  bgHoverColor?: string;
  selectedAmount?: string | number | undefined;
  showOtherInput?: boolean;
  textColor?: string;
};

const getThemeButtonColors = ({
  amount,
  bgColor,
  bgHoverColor,
  selectedAmount,
  showOtherInput,
  textColor,
}: ThemeButtonProps) => {
  if (bgColor && bgHoverColor && textColor) {
    const activeStyles = {
      backgroundColor: bgColor,
      borderColor: bgColor,
      borderWidth: '2px',
      color: textColor,
    };

    // Solid background if nothing is selected or this button has been selected
    if ((!selectedAmount && !showOtherInput) || selectedAmount === amount) {
      return {
        _active: activeStyles,
        _hover: {
          backgroundColor: bgHoverColor,
        },
        backgroundColor: bgColor,
        borderColor: bgColor,
        color: textColor,
      };
    }

    // If 1 button is selected, then every other button is just greyish
    return {
      _active: activeStyles,
      _hover: activeStyles,
      backgroundColor: 'neutral.100',
      borderColor: 'neutral.100',
      borderWidth: '2px',
      color: 'neutral.600',
    };
  }
  return {};
};

