type ActionPageBodyProps = {
  actionPage: PublicActionPage;
  actionPageFormBlockCaption?: React.ReactNode;
  amounts: ActionPageFinanceBlockProps['amounts'];
  donationCaption?: React.ReactNode;
  formMaxWidth?: string;
  frequencies: SourceFrequency[];
  fundIdsOverride: string[];
  initialAmount: number;
  isCustomDomain?: boolean;
  isEmbedded?: boolean;
  isLoading: boolean;
  isPastEvent: boolean;
  isPreview?: boolean;
  showAmountSelector?: boolean;
  showFrequencyOnStackedSubmissionButton?: boolean;
} & WithChildren;

export const ActionPageBody = ({
  actionPage,
  actionPageFormBlockCaption,
  amounts,
  children,
  donationCaption,
  formMaxWidth,
  frequencies,
  fundIdsOverride,
  initialAmount,
  isCustomDomain = false,
  isEmbedded = false,
  isLoading,
  isPastEvent,
  isPreview = false,
  showAmountSelector = true,
  showFrequencyOnStackedSubmissionButton = true,
}: ActionPageBodyProps) => {
  const turnstileEnabled =
    useFeatureFlag('actionPages.turnstile', false, actionPage.account.id) && !isPreview;

  const turnstileInteractiveEnabled =
    useFeatureFlag('actionPages.turnstileInteractive', false, actionPage.account.id) && !isPreview;

  useParsedScript({
    parent: document.head,
    script: actionPage?.account?.accountConfiguration?.headerScript,
  });

  useParsedScript({
    parent: document.body,
    script: actionPage?.account?.accountConfiguration?.bodyScript,
  });

  useEffect(() => {
    const anchor = window.location.hash;

    if (anchor) {
      setTimeout(() => {
        document
          .querySelector(anchor)
          ?.scrollIntoView({ behavior: 'smooth', block: 'start', inline: 'nearest' });
      }, 500);
    }
  }, []);

  const formFooterClasses = useMemo(() => {
    const alignSelf =
      actionPage.formAlignment === 'center'
        ? 'center'
        : actionPage.formAlignment === 'left'
          ? 'self-start'
          : 'self-end';
    return clsx(
      'mt-8 flex w-full justify-center px-4 sm:px-8',
      { [alignSelf]: !!formMaxWidth },
      {}
    );
  }, [actionPage.formAlignment, formMaxWidth]);

  // Since the formMaxWidth is driven by JS, we can't use tailwind arbitrary values
  // as they are computed at build-time
  const formMaxWidthStyle: CSSProperties | undefined = useMemo(() => {
    if (formMaxWidth) {
      return { maxWidth: formMaxWidth };
    }
    return undefined;
  }, [formMaxWidth]);

  return (
    <Suspense
      fallback={
        <div className="flex h-full w-full items-center justify-center p-8">
          <Loading />
        </div>
      }
    >
      {!isPreview && (turnstileEnabled || turnstileInteractiveEnabled) ? (
        <TurnstileChallenge appearance={turnstileInteractiveEnabled ? 'always' : undefined} />
      ) : null}
      <ActionPagePotentialSubmitter actionPage={actionPage} />

      <ActionPageFormPresentation
        actionPage={actionPage}
        actionPageFormBlockCaption={actionPageFormBlockCaption}
        amounts={amounts}
        donationCaption={donationCaption}
        formMaxWidth={formMaxWidth}
        frequencies={frequencies}
        fundIdsOverride={fundIdsOverride}
        initialAmount={initialAmount}
        isCustomDomain={isCustomDomain}
        isEmbedded={isEmbedded}
        isLoading={isLoading}
        isPastEvent={isPastEvent}
        isPreview={isPreview}
        showAmountSelector={showAmountSelector}
        showFrequencyOnStackedSubmissionButton={showFrequencyOnStackedSubmissionButton}
      >
        {children}
      </ActionPageFormPresentation>

      <div className={formFooterClasses} id="action-page-form-footer" style={formMaxWidthStyle}>
        <div className="flex flex-col items-center">
          <SecureNotice actionPage={actionPage} isEmbedded={isEmbedded} />
          <PrivacyPolicyNotice />
        </div>
      </div>
    </Suspense>
  );
};

