import { SourceFrequency } from '@domain/entry';
import { PublicActionPage } from '@domain/publicActionPage';
import { useTotalAmount } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { computeTotalFees } from '@utils/computeTotalFees';
import { isDonationPage } from '@utils/isDonationPage/isDonationPage';
import valid from 'card-validator';
import clsx from 'clsx';
import { useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { FuturePledgeProvider } from 'src/builder/PublicActionPage/components/DonationSelector/components/FuturePledgeBanner';
import { ExpressCheckout } from 'src/builder/PublicActionPage/components/ExpressCheckout';
import { AttendeeDetails } from '../../../EventPageLayout/AttendeeDetails/AttendeeDetails';
import { useAttendeeDetails } from '../../../EventPageLayout/AttendeeDetails/hooks';
import { ActionPageDonationBlock } from '../ActionPageDonationBlock/ActionPageDonationBlock';
import { ActionPageFinanceBlockProps } from '../ActionPageFinanceBlock';
import { ActionPageFormBlock } from '../ActionPageForm';
import { ActionPagePaymentBlock } from '../ActionPagePaymentBlock';
import { CoverTheFees } from '../components/CoverTheFees';
import { useTicketTotalAmount } from '../hooks';
import { DonorSessionBanner } from './DonorSessionBanner';

type ActionPagePresentationProps = WithChildren & {
  actionPage: PublicActionPage;
  actionPageFormBlockCaption?: React.ReactNode;
  amounts: ActionPageFinanceBlockProps['amounts'];
  donationCaption?: React.ReactNode;
  form?: string;
  formMaxWidth?: string;
  frequencies: SourceFrequency[];
  fundIdsOverride: string[];
  initialAmount: number;
  isCustomDomain?: boolean;
  isEmbedded: boolean;
  isLoading: boolean;
  isPastEvent: boolean;
  isPreview?: boolean;
  onSetAmount?: ActionPageFinanceBlockProps['onSetAmount'];
  showAmountSelector?: boolean;
  showFrequencyOnStackedSubmissionButton?: boolean;
  showLoadingOnAmounts?: boolean;
  showStackedSubmissionButton?: boolean;
};

export const ActionPageFormPresentation = ({
  actionPage,
  actionPageFormBlockCaption,
  amounts,
  children,
  donationCaption,
  form,
  formMaxWidth,
  frequencies,
  fundIdsOverride,
  initialAmount,
  isCustomDomain,
  isEmbedded,
  isLoading,
  isPastEvent,
  isPreview = false,
  onSetAmount,
  showAmountSelector = true,
  showFrequencyOnStackedSubmissionButton = true,
  showLoadingOnAmounts,
  showStackedSubmissionButton,
}: ActionPagePresentationProps) => {
  const isDonation = isDonationPage(actionPage?.pageType);
  const isEvent = isDonation && actionPage?.event !== null;
  const { watch } = useFormContext();
  const donorProfile = watch('donorProfile');
  const isInUpgradeChain = watch('isInUpgradeChain');
  const cardNumber = watch('vaultToken');
  const { feeCoverType } = actionPage.paymentConfiguration || {};
  const { actionElementColorPrimary } = actionPage.designConfiguration;
  const formCardType = watch('cardType');
  const country = watch('addressAttributes.country');
  const type = watch('type');
  const expressCheckoutMethod = isPreview ? null : watch('expressCheckoutMethod');
  const promoCodeDiscount = watch('promoCodeDiscount');

  const cardType: 'american-express' | 'visa' | 'mastercard' | 'discover' | string | undefined =
    useMemo(() => valid.number(cardNumber)?.card?.type, [cardNumber]);
  const donationAmount = useTotalAmount();
  const ticketAmount = useTicketTotalAmount(actionPage);
  const totalAmount = donationAmount + ticketAmount;
  const { attendeeDetails, updateAttendeeDetails } = useAttendeeDetails({
    actionPage,
  });
  const { acceptsDonationsForAllPurchaseTypes } = actionPage.generalConfiguration;

  const totalFees = useMemo(() => {
    const card = formCardType || cardType;
    return computeTotalFees({
      amount: Math.max((totalAmount ?? 0) - (promoCodeDiscount ?? 0), 0),
      billingAgreements: actionPage?.billingAgreements,
      cardType: !card || card === 'american_express' ? 'american-express' : card,
      isInternational: country !== 'US',
      paymentType: type,
    });
  }, [
    actionPage?.billingAgreements,
    cardType,
    country,
    formCardType,
    promoCodeDiscount,
    totalAmount,
    type,
  ]);

  const showPaymentBlock =
    !!expressCheckoutMethod || !isEvent || (isEvent && isPastEvent) || (isEvent && totalAmount > 0);
  const columnClasses = clsx(
    'flex flex-col',
    isPastEvent
      ? 'mt-4'
      : (!isPreview && !donorProfile) || !acceptsDonationsForAllPurchaseTypes
        ? 'mt-4'
        : 'mt-12'
  );

  return (
    <FuturePledgeProvider>
      <div
        className="flex flex-col"
        id="action-page-form-section"
        style={{ maxWidth: formMaxWidth }}
      >
        {!isPreview && !isInUpgradeChain ? (
          <DonorSessionBanner actionPage={actionPage} isPastEvent={isPastEvent} />
        ) : null}
        <div className={columnClasses} id="action-page-form-and-payment-fields">
          <div className="relative grid h-full !leading-normal transition-[grid-template-rows] duration-200 ease-in-out">
            <div className="overflow-hidden">
              <ActionPageDonationBlock
                actionPage={actionPage}
                amounts={amounts}
                donationCaption={donationCaption}
                frequencies={frequencies}
                fundIdsOverride={fundIdsOverride}
                initialAmount={initialAmount}
                // isEmbedded={isEmbedded}
                // isLoading={isLoading}
                onSetAmount={onSetAmount}
                showAmountSelector={showAmountSelector}
                showLoadingOnAmounts={showLoadingOnAmounts}
                totalFees={totalFees}
              />
            </div>
          </div>
          <CoverTheFees
            actionElementColorPrimary={actionElementColorPrimary}
            amount={totalAmount}
            billingAgreements={actionPage.billingAgreements}
            cardType={formCardType || cardType}
            feeCoverType={actionPage.pageType === 'storefront' ? 'required' : feeCoverType}
            pageType={actionPage.pageType}
            paymentType={type}
          />
        </div>

        <div className="mt-8 flex flex-col">
          <ExpressCheckout
            actionPage={actionPage}
            fieldPrefix="addressAttributes"
            fieldPrefixDelimiter="."
            isCustomDomain={isCustomDomain}
            isEmbedded={isEmbedded}
            isLoading={isLoading}
            isPreview={isPreview}
            showOrDivider
            showPaymentBlock={showPaymentBlock}
            showPayWithCardOrBankButton={false}
            showSignInPrompt={false}
          />
        </div>

        <div className="flex flex-col">
          {children}
          <ActionPageFormBlock actionPage={actionPage} isPreview={isPreview} />
        </div>

        <div className="flex flex-col" id="attendee-details">
          <AttendeeDetails
            actionPage={actionPage}
            attendeeDetails={attendeeDetails}
            updateAttendeeDetails={updateAttendeeDetails}
          />
        </div>

        <div className="flex flex-col">
          <ActionPagePaymentBlock
            actionPage={actionPage}
            caption={actionPageFormBlockCaption}
            form={isPreview ? undefined : form}
            isEmbedded={isEmbedded}
            isEvent={isEvent}
            isLoading={isLoading}
            isPreview={isPreview}
            showFrequencyOnSubmissionButton={showFrequencyOnStackedSubmissionButton}
            showPaymentBlock={showPaymentBlock}
            showSubmissionButton={showStackedSubmissionButton}
            totalFees={totalFees}
          />
        </div>
      </div>
    </FuturePledgeProvider>
  );
};

