type ActionPageLayoutProps = {
  actionPage?: PublicActionPage;
  isCustomDomain?: boolean;
  isEmbedded?: boolean;
  isPreview?: boolean;
  isRestricted?: boolean;
};

const ActionPageCustomCSS = ({ actionPage }: { actionPage?: PublicActionPage }) => {
  const customCss = actionPage?.generalConfiguration.customCss;
  const insertCustomCss = !!actionPage?.account?.allowCustomCss && !!customCss;

  if (insertCustomCss) {
    return <style>{customCss}</style>;
  }
  return null;
};

export const ActionPageLayout = memo(
  ({ actionPage, isCustomDomain, isPreview }: Partial<ActionPageLayoutProps>) => {
    const actionPageClasses = clsx('flex w-full flex-col bg-neutral-100 @container', {
      'event-page-preview': isPreview,
    });

    useEffect(() => {
      useActionPageStore.setState(() => ({ content: actionPage?.content }));
    }, [actionPage]);

    if (!actionPage) {
      return <Loading />;
    }

    return (
      <div className={actionPageClasses}>
        <ActionPageTwitterScript />
        {!isPreview && (
