import { RefObject } from 'react';
import { FieldValues, FormProvider, UseFormReturn } from 'react-hook-form';
import { UseEnhancedFormProps, useEnhancedForm } from './hooks/useEnhancedForm';

export type FormProps<T extends FieldValues> = UseEnhancedFormProps<T> & {
  children: ((methods: UseFormReturn<T, object>) => React.ReactNode) | React.ReactNode;
  formRef?: RefObject<HTMLFormElement>;
  id?: string;
  noValidate?: boolean;
  onSubmit: (values: T, methods: UseFormReturn<T, object>) => void;
};

export function Form<T extends FieldValues>({
  children,
  context,
  enableReinitialize,
  formRef,
  id,
  initialValues,
  mode = 'onBlur',
  /**
   * To disable html5 validation, set `noValidate` to `true`
   */
  noValidate = false,
  onSubmit,
  schema,
  serverError,
  ...boxProps
}: FormProps<T>) {
  const methods = useEnhancedForm({
    context,
    enableReinitialize,
    initialValues,
    mode,
    schema,
    serverError,
  });

  const refProps = formRef ? { ref: formRef } : {};

  return (
    <FormProvider {...methods}>
      <form
        noValidate={noValidate}
        {...boxProps}
        id={id}
        {...refProps}
        onSubmit={methods.handleSubmit((values) => onSubmit(values, methods))}
      >
        {typeof children === 'function' ? children(methods) : children}
      </form>
    </FormProvider>
  );
}

